package com.example.quicklogin;

import android.content.Context;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.text.TextUtils;
import android.util.Patterns;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

public class LoginActivity extends AppCompatActivity {

    private static final String PREFS_NAME = "login_prefs";
    private static final String KEY_EMAIL = "key_email";
    private static final String KEY_TOKEN = "key_token";

    private EditText emailInput;
    private EditText passwordInput;
    private Button loginButton;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        emailInput = findViewById(R.id.emailInput);
        passwordInput = findViewById(R.id.passwordInput);
        loginButton = findViewById(R.id.loginButton);

        restoreSavedCredentials();

        loginButton.setOnClickListener(v -> attemptLogin());
    }

    private void restoreSavedCredentials() {
        SharedPreferences prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        String savedEmail = prefs.getString(KEY_EMAIL, null);
        String savedToken = prefs.getString(KEY_TOKEN, null);

        if (!TextUtils.isEmpty(savedEmail) && !TextUtils.isEmpty(savedToken)) {
            emailInput.setText(savedEmail);
            onLoginSuccess(savedEmail, savedToken);
        }
    }

    private void attemptLogin() {
        String email = emailInput.getText().toString().trim();
        String password = passwordInput.getText().toString();

        if (TextUtils.isEmpty(email) || !Patterns.EMAIL_ADDRESS.matcher(email).matches()) {
            emailInput.setError("Enter a valid email");
            emailInput.requestFocus();
            return;
        }

        if (TextUtils.isEmpty(password)) {
            passwordInput.setError("Enter your password");
            passwordInput.requestFocus();
            return;
        }

        String token = performFakeAuth(email, password);
        if (token != null) {
            saveCredentials(email, token);
            onLoginSuccess(email, token);
        } else {
            Toast.makeText(this, "Invalid credentials", Toast.LENGTH_SHORT).show();
        }
    }

    private String performFakeAuth(String email, String password) {
        if ("demo@example.com".equalsIgnoreCase(email) && "password123".equals(password)) {
            return "demo-auth-token-123456";
        }
        return null;
    }

    private void saveCredentials(String email, String token) {
        SharedPreferences prefs = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        prefs.edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_TOKEN, token)
                .apply();
    }

    private void onLoginSuccess(String email, String token) {
        Toast.makeText(this, "Logged in as " + email, Toast.LENGTH_SHORT).show();
        // TODO: Navigate to the next screen and use token for authenticated requests.
    }
}

package com.example.quicklogin;

import android.content.Context;
import android.content.SharedPreferences;

public class SessionManager {

    private static final String PREFS_NAME = "login_prefs";
    private static final String KEY_EMAIL = "key_email";
    private static final String KEY_TOKEN = "key_token";

    private final SharedPreferences prefs;

    public SessionManager(Context context) {
        prefs = context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
    }

    public void saveSession(String email, String token) {
        prefs.edit()
                .putString(KEY_EMAIL, email)
                .putString(KEY_TOKEN, token)
                .apply();
    }

    public String getEmail() {
        return prefs.getString(KEY_EMAIL, null);
    }

    public String getToken() {
        return prefs.getString(KEY_TOKEN, null);
    }

    public boolean isLoggedIn() {
        return getEmail() != null && getToken() != null;
    }

    public void clearSession() {
        prefs.edit().clear().apply();
    }
}

package com.example.quicklogin;

import android.content.Intent;
import android.os.Bundle;

import androidx.appcompat.app.AppCompatActivity;

public class SplashActivity extends AppCompatActivity {

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        SessionManager sessionManager = new SessionManager(this);
        if (sessionManager.isLoggedIn()) {
            startActivity(new Intent(this, HomeActivity.class));
        } else {
            startActivity(new Intent(this, LoginActivity.class));
        }
        finish();
    }
}

package com.example.quicklogin;

import android.os.Bundle;
import android.widget.Button;
import android.widget.TextView;

import androidx.appcompat.app.AppCompatActivity;

public class HomeActivity extends AppCompatActivity {

    private SessionManager sessionManager;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_home);

        sessionManager = new SessionManager(this);

        TextView welcomeText = findViewById(R.id.welcomeText);
        Button logoutButton = findViewById(R.id.logoutButton);

        String email = sessionManager.getEmail();
        welcomeText.setText(email != null ? "Welcome, " + email : "Welcome");

        logoutButton.setOnClickListener(v -> {
            sessionManager.clearSession();
            finish();
        });
    }
}